import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.Pywvta2k.js";const y=JSON.parse('{"title":"上经三十卦与人体对应","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/07-六十四卦人体全对应/01-上经三十卦与人体.md","filePath":"tcm-data/09-医易同源/07-六十四卦人体全对应/01-上经三十卦与人体.md","lastUpdated":1781084559000}'),r={name:"tcm-data/09-医易同源/07-六十四卦人体全对应/01-上经三十卦与人体.md"};function d(s,t,g,o,i,h){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="上经三十卦与人体对应" tabindex="-1">上经三十卦与人体对应 <a class="header-anchor" href="#上经三十卦与人体对应" aria-label="Permalink to &quot;上经三十卦与人体对应&quot;">​</a></h1><blockquote><p>从乾卦到离卦——天道之始，人体之基 《易经》上经以天道为主，对应人体的先天体质和根本功能</p></blockquote><hr><h2 id="概览-上经三十卦" tabindex="-1">概览：上经三十卦 <a class="header-anchor" href="#概览-上经三十卦" aria-label="Permalink to &quot;概览：上经三十卦&quot;">​</a></h2><p><strong>乾坤屯蒙需讼师，比小畜兮履泰否。 同人大有谦豫随，蛊临观兮噬嗑贲。 剥复无妄大畜颐，大过坎离三十备。</strong></p><hr><h2 id="一、乾坤——天地之门-人体总纲" tabindex="-1">一、乾坤——天地之门（人体总纲） <a class="header-anchor" href="#一、乾坤——天地之门-人体总纲" aria-label="Permalink to &quot;一、乾坤——天地之门（人体总纲）&quot;">​</a></h2><h3 id="䷀乾——天行健" tabindex="-1">䷀乾——天行健 <a class="header-anchor" href="#䷀乾——天行健" aria-label="Permalink to &quot;䷀乾——天行健&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>卦象</strong></td><td style="text-align:left;">☰☰ 六爻皆阳</td></tr><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">阳气、元气、督脉</td></tr><tr><td style="text-align:left;"><strong>对应人体</strong></td><td style="text-align:left;">头、脊柱、督脉、全身阳气</td></tr><tr><td style="text-align:left;"><strong>生理</strong></td><td style="text-align:left;">&quot;天行健，君子以自强不息&quot;——阳气的主动运行</td></tr><tr><td style="text-align:left;"><strong>病理</strong></td><td style="text-align:left;">阳虚则沉、阳气不升则头倾（普光头前倾与此相关）</td></tr><tr><td style="text-align:left;"><strong>药物</strong></td><td style="text-align:left;">附子（纯阳之品）、鹿茸（督脉用药）</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">坎水寒→乾阳不足→头前倾。天魂汤法即补乾阳。</td></tr></tbody></table><h3 id="䷁坤——地势坤" tabindex="-1">䷁坤——地势坤 <a class="header-anchor" href="#䷁坤——地势坤" aria-label="Permalink to &quot;䷁坤——地势坤&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>卦象</strong></td><td style="text-align:left;">☷☷ 六爻皆阴</td></tr><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">阴气、脾土、任脉</td></tr><tr><td style="text-align:left;"><strong>对应人体</strong></td><td style="text-align:left;">腹、肌肉、任脉、脾胃系统</td></tr><tr><td style="text-align:left;"><strong>生理</strong></td><td style="text-align:left;">&quot;厚德载物&quot;——脾主运化，承载四脏</td></tr><tr><td style="text-align:left;"><strong>病理</strong></td><td style="text-align:left;">坤土湿盛则面色暗沉如尘土（普光）；坤土虚则不运（普明腹胀）</td></tr><tr><td style="text-align:left;"><strong>药物</strong></td><td style="text-align:left;">人参（补坤土）、茯苓（泻坤湿）</td></tr><tr><td style="text-align:left;"><strong>普光/普明</strong></td><td style="text-align:left;">⭐ 两人都涉及坤卦——普光土湿，普明土虚</td></tr></tbody></table><h3 id="乾坤合论——人体的大阴阳" tabindex="-1">乾坤合论——人体的大阴阳 <a class="header-anchor" href="#乾坤合论——人体的大阴阳" aria-label="Permalink to &quot;乾坤合论——人体的大阴阳&quot;">​</a></h3><blockquote><p><strong>乾为首，坤为腹。</strong>（《说卦传》）</p></blockquote><p><strong>在人体上</strong>：</p><ul><li>乾阳不足 → 头前倾、精神不振、督脉寒</li><li>坤阴过盛 → 腹部肥大、湿浊内停</li><li>乾坤交泰（䷊）→ 头清腹暖，阳气下降，阴气上升</li></ul><hr><h2 id="二、屯蒙——生命的开始" tabindex="-1">二、屯蒙——生命的开始 <a class="header-anchor" href="#二、屯蒙——生命的开始" aria-label="Permalink to &quot;二、屯蒙——生命的开始&quot;">​</a></h2><h3 id="䷂屯——刚柔始交" tabindex="-1">䷂屯——刚柔始交 <a class="header-anchor" href="#䷂屯——刚柔始交" aria-label="Permalink to &quot;䷂屯——刚柔始交&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>卦象</strong></td><td style="text-align:left;">震☳下坎☵上——雷在水下</td></tr><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>肾水与肝木的关系</strong>——水寒木郁</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">⭐ 坎水寒+震木郁 = 屯卦——普光的核心病机之一</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;"><strong>天魂汤（温坎水以升震木）</strong></td></tr><tr><td style="text-align:left;"><strong>爻辞启示</strong></td><td style="text-align:left;">&quot;君子以经纶&quot;——需周详调理，不可急于求成</td></tr></tbody></table><h3 id="䷃蒙——山下出泉" tabindex="-1">䷃蒙——山下出泉 <a class="header-anchor" href="#䷃蒙——山下出泉" aria-label="Permalink to &quot;䷃蒙——山下出泉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>卦象</strong></td><td style="text-align:left;">坎☵下艮☶上——水在山下</td></tr><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>肾水与脾胃的关系</strong>——水停中焦则蒙昧不清</td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">头昏、身体沉重、湿浊上蒙</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">黄芽汤（运转中轴，化湿升清）</td></tr></tbody></table><hr><h2 id="三、需讼师比——外邪入侵与正气抗邪" tabindex="-1">三、需讼师比——外邪入侵与正气抗邪 <a class="header-anchor" href="#三、需讼师比——外邪入侵与正气抗邪" aria-label="Permalink to &quot;三、需讼师比——外邪入侵与正气抗邪&quot;">​</a></h2><h3 id="䷄需——云上于天-等待" tabindex="-1">䷄需——云上于天（等待） <a class="header-anchor" href="#䷄需——云上于天-等待" aria-label="Permalink to &quot;䷄需——云上于天（等待）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">乾☰下坎☵上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">阳气欲升，寒水在上——阳虚外感</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;"><strong>麻黄附子细辛汤</strong>（太少两感）</td></tr></tbody></table><h3 id="䷅讼——天水违行-相争" tabindex="-1">䷅讼——天水违行（相争） <a class="header-anchor" href="#䷅讼——天水违行-相争" aria-label="Permalink to &quot;䷅讼——天水违行（相争）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坎☵下乾☰上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">阴阳不交，上下相争——水火不交</td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">上热下寒、寒热错杂</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">⭐ 上热（口渴前胸出汗）+ 下寒（腰凉）→ 讼卦</td></tr></tbody></table><h3 id="䷆师——地中有水-蓄积" tabindex="-1">䷆师——地中有水（蓄积） <a class="header-anchor" href="#䷆师——地中有水-蓄积" aria-label="Permalink to &quot;䷆师——地中有水（蓄积）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坎☵下坤☷上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>水湿内停</strong>——地（坤）上有水（坎）</td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">水肿、白带多、阴囊潮湿</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">五苓散、茯苓泽泻</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">阴囊潮湿+脚气→师卦</td></tr><tr><td style="text-align:left;"><strong>普明</strong></td><td style="text-align:left;">白带多→师卦</td></tr></tbody></table><h3 id="䷇比——地上有水-亲和" tabindex="-1">䷇比——地上有水（亲和） <a class="header-anchor" href="#䷇比——地上有水-亲和" aria-label="Permalink to &quot;䷇比——地上有水（亲和）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坤☷下坎☵上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">水与土和——脾肾调和</td></tr><tr><td style="text-align:left;"><strong>健康状态</strong></td><td style="text-align:left;">肾阳温脾→水湿得化（欲达到的状态）</td></tr></tbody></table><hr><h2 id="四、小畜履泰否——气机的关键转折" tabindex="-1">四、小畜履泰否——气机的关键转折 <a class="header-anchor" href="#四、小畜履泰否——气机的关键转折" aria-label="Permalink to &quot;四、小畜履泰否——气机的关键转折&quot;">​</a></h2><h3 id="䷈小畜——风行天上-小有积蓄" tabindex="-1">䷈小畜——风行天上（小有积蓄） <a class="header-anchor" href="#䷈小畜——风行天上-小有积蓄" aria-label="Permalink to &quot;䷈小畜——风行天上（小有积蓄）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">乾☰下巽☴上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">天（阳气）被风（肝气）所蓄——<strong>肝气郁结的初始阶段</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">轻度胸闷、情绪不畅</td></tr></tbody></table><h3 id="䷉履——上天下泽-践行" tabindex="-1">䷉履——上天下泽（践行） <a class="header-anchor" href="#䷉履——上天下泽-践行" aria-label="Permalink to &quot;䷉履——上天下泽（践行）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">兑☱下乾☰上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肺（兑）与阳气（乾）的关系——<strong>肺气不降则阳气不敛</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">咳嗽、气短</td></tr></tbody></table><h3 id="䷊泰——天地交泰-最健康的状态" tabindex="-1">䷊泰——天地交泰（最健康的状态） <a class="header-anchor" href="#䷊泰——天地交泰-最健康的状态" aria-label="Permalink to &quot;䷊泰——天地交泰（最健康的状态）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">乾☰下坤☷上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>阳气下降、阴气上升——阴阳交泰</strong></td></tr><tr><td style="text-align:left;"><strong>健康状态</strong></td><td style="text-align:left;">⭐ <strong>人体最理想的健康模型：上清（头清）下温（腹暖）</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">所有调节&quot;上热下寒&quot;的方剂都指向泰卦</td></tr><tr><td style="text-align:left;"><strong>普光治疗目标</strong></td><td style="text-align:left;">从&quot;否&quot;到&quot;泰&quot;</td></tr></tbody></table><h3 id="䷋否——天地不交-最病的状态" tabindex="-1">䷋否——天地不交（最病的状态） <a class="header-anchor" href="#䷋否——天地不交-最病的状态" aria-label="Permalink to &quot;䷋否——天地不交（最病的状态）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坤☷下乾☰上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>阳气在上不降、阴气在下不升——天地隔绝</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;"><strong>上热下寒</strong>——头热口渴+腰凉脚冷</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">⭐ <strong>普光的&quot;否卦&quot;状态</strong>——前胸出汗（阳在上）+腰凉（阴在下）</td></tr><tr><td style="text-align:left;"><strong>治疗核心</strong></td><td style="text-align:left;"><strong>恢复&quot;泰&quot;</strong> = 金鼎汤潜降相火（引阳下降）+ 天魂汤温升肾水（引阴上升）</td></tr></tbody></table><h3 id="普光的-否→泰-治疗路径" tabindex="-1">普光的&quot;否→泰&quot;治疗路径 <a class="header-anchor" href="#普光的-否→泰-治疗路径" aria-label="Permalink to &quot;普光的&quot;否→泰&quot;治疗路径&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前：否䷋（阳在上、阴在下）</span></span>
<span class="line"><span>     ⬇</span></span>
<span class="line"><span>     金鼎汤降相火（龙牡白芍）→ 引阳下降</span></span>
<span class="line"><span>     ⬇</span></span>
<span class="line"><span>     天魂汤温肾水（附子桂枝）→ 引阴上升</span></span>
<span class="line"><span>     ⬇</span></span>
<span class="line"><span>     ↓↓  在关元处交会  ↑↑</span></span>
<span class="line"><span>     ⬇</span></span>
<span class="line"><span>目标：泰䷊（阴阳交泰、水火既济）</span></span></code></pre></div><hr><h2 id="五、同人大有谦豫随——脾胃与气血" tabindex="-1">五、同人大有谦豫随——脾胃与气血 <a class="header-anchor" href="#五、同人大有谦豫随——脾胃与气血" aria-label="Permalink to &quot;五、同人大有谦豫随——脾胃与气血&quot;">​</a></h2><h3 id="䷌同人——天与火-光明普照" tabindex="-1">䷌同人——天与火（光明普照） <a class="header-anchor" href="#䷌同人——天与火-光明普照" aria-label="Permalink to &quot;䷌同人——天与火（光明普照）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">离☲下乾☰上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">心（离）与阳气（乾）——<strong>心阳充足则精神好</strong></td></tr></tbody></table><h3 id="䷍大有——火在天上-丰收" tabindex="-1">䷍大有——火在天上（丰收） <a class="header-anchor" href="#䷍大有——火在天上-丰收" aria-label="Permalink to &quot;䷍大有——火在天上（丰收）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">乾☰下离☲上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">阳气推动心火——<strong>气血充足的状态</strong></td></tr></tbody></table><h3 id="䷎谦——地中有山-谦卑" tabindex="-1">䷎谦——地中有山（谦卑） <a class="header-anchor" href="#䷎谦——地中有山-谦卑" aria-label="Permalink to &quot;䷎谦——地中有山（谦卑）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">艮☶下坤☷上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">胃（艮）在脾（坤）之下——<strong>胃气下降的正常状态</strong></td></tr></tbody></table><h3 id="䷏豫——雷出地奋-愉悦" tabindex="-1">䷏豫——雷出地奋（愉悦） <a class="header-anchor" href="#䷏豫——雷出地奋-愉悦" aria-label="Permalink to &quot;䷏豫——雷出地奋（愉悦）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坤☷下震☳上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>肝（震）气从脾（坤）中升发——疏泄正常</strong></td></tr><tr><td style="text-align:left;"><strong>健康</strong></td><td style="text-align:left;">心情愉悦，气机舒畅</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">震木得升→心情好、目润、筋柔</td></tr></tbody></table><h3 id="䷐随——泽中有雷-跟随" tabindex="-1">䷐随——泽中有雷（跟随） <a class="header-anchor" href="#䷐随——泽中有雷-跟随" aria-label="Permalink to &quot;䷐随——泽中有雷（跟随）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">震☳下兑☱上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肝（震）随肺（兑）降——<strong>金木相随，升降有序</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">金鼎汤（降肺金以敛肝木）</td></tr></tbody></table><hr><h2 id="六、蛊临观——杂病之源" tabindex="-1">六、蛊临观——杂病之源 <a class="header-anchor" href="#六、蛊临观——杂病之源" aria-label="Permalink to &quot;六、蛊临观——杂病之源&quot;">​</a></h2><h3 id="䷑蛊——山下有风-腐败" tabindex="-1">䷑蛊——山下有风（腐败） <a class="header-anchor" href="#䷑蛊——山下有风-腐败" aria-label="Permalink to &quot;䷑蛊——山下有风（腐败）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">巽☴下艮☶上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>风（肝）在山（胃）下——肝气犯胃</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">腹胀、嗳气、消化不良</td></tr><tr><td style="text-align:left;"><strong>普明</strong></td><td style="text-align:left;">饭后腹胀→蛊卦</td></tr></tbody></table><h3 id="䷒临——泽上有地-临近" tabindex="-1">䷒临——泽上有地（临近） <a class="header-anchor" href="#䷒临——泽上有地-临近" aria-label="Permalink to &quot;䷒临——泽上有地（临近）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">兑☱下坤☷上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肺（兑）与脾（坤）——<strong>土生金</strong></td></tr></tbody></table><h3 id="䷓观——风行地上-观察" tabindex="-1">䷓观——风行地上（观察） <a class="header-anchor" href="#䷓观——风行地上-观察" aria-label="Permalink to &quot;䷓观——风行地上（观察）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坤☷下巽☴上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">脾（坤）与胆（巽）——<strong>食物的消化吸收需要胆汁的参与</strong></td></tr></tbody></table><hr><h2 id="七、噬嗑贲剥复——循环往复" tabindex="-1">七、噬嗑贲剥复——循环往复 <a class="header-anchor" href="#七、噬嗑贲剥复——循环往复" aria-label="Permalink to &quot;七、噬嗑贲剥复——循环往复&quot;">​</a></h2><h3 id="䷔噬嗑——雷电噬嗑-咬合" tabindex="-1">䷔噬嗑——雷电噬嗑（咬合） <a class="header-anchor" href="#䷔噬嗑——雷电噬嗑-咬合" aria-label="Permalink to &quot;䷔噬嗑——雷电噬嗑（咬合）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">震☳下离☲上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肝（震）与心（离）——<strong>木生火，心肝的关系</strong></td></tr></tbody></table><h3 id="䷕贲——山下有火-装饰" tabindex="-1">䷕贲——山下有火（装饰） <a class="header-anchor" href="#䷕贲——山下有火-装饰" aria-label="Permalink to &quot;䷕贲——山下有火（装饰）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">离☲下艮☶上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">心（离）与胃（艮）——<strong>面部气血的荣润</strong></td></tr></tbody></table><h3 id="䷖剥——山附于地-剥落" tabindex="-1">䷖剥——山附于地（剥落） <a class="header-anchor" href="#䷖剥——山附于地-剥落" aria-label="Permalink to &quot;䷖剥——山附于地（剥落）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坤☷下艮☶上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>一阳（艮）在五阴（坤）之上——阳气将尽</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">久病、老年、虚衰</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">一阳在上（上热），五阴在下（下寒）——剥卦</td></tr><tr><td style="text-align:left;"><strong>治疗</strong></td><td style="text-align:left;"><strong>复卦（一阳来复）</strong>——附子温下焦</td></tr></tbody></table><h3 id="䷗复——地中有雷-一阳来复" tabindex="-1">䷗复——地中有雷（一阳来复） <a class="header-anchor" href="#䷗复——地中有雷-一阳来复" aria-label="Permalink to &quot;䷗复——地中有雷（一阳来复）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">震☳下坤☷上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>最重要的养生卦象——一阳从地下生出</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">冬至、子时、肾阳</td></tr><tr><td style="text-align:left;"><strong>养生</strong></td><td style="text-align:left;">冬至宜静养、子时宜安睡——让这一阳生根发芽</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;"><strong>附子的作用就是&quot;一阳来复&quot;——温肾阳以生土中之阳</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">天魂汤、四逆汤</td></tr></tbody></table><hr><h2 id="八、无妄大畜颐大过——养生要旨" tabindex="-1">八、无妄大畜颐大过——养生要旨 <a class="header-anchor" href="#八、无妄大畜颐大过——养生要旨" aria-label="Permalink to &quot;八、无妄大畜颐大过——养生要旨&quot;">​</a></h2><h3 id="䷘无妄——天下雷行-无妄为" tabindex="-1">䷘无妄——天下雷行（无妄为） <a class="header-anchor" href="#䷘无妄——天下雷行-无妄为" aria-label="Permalink to &quot;䷘无妄——天下雷行（无妄为）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">震☳下乾☰上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肝（震）在阳气（乾）之下——<strong>顺其自然，不可妄为</strong></td></tr><tr><td style="text-align:left;"><strong>养生</strong></td><td style="text-align:left;">不折腾是最好的养生</td></tr></tbody></table><h3 id="䷙大畜——天在山中-大积蓄" tabindex="-1">䷙大畜——天在山中（大积蓄） <a class="header-anchor" href="#䷙大畜——天在山中-大积蓄" aria-label="Permalink to &quot;䷙大畜——天在山中（大积蓄）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">乾☰下艮☶上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">阳气（乾）蓄积在胃（艮）——<strong>积蓄能量</strong></td></tr></tbody></table><h3 id="䷚颐——山下有雷-养生" tabindex="-1">䷚颐——山下有雷（养生） <a class="header-anchor" href="#䷚颐——山下有雷-养生" aria-label="Permalink to &quot;䷚颐——山下有雷（养生）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">震☳下艮☶上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>颐卦=养生的专属卦象——养正、养气、养德</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">饮食、呼吸、节欲</td></tr><tr><td style="text-align:left;"><strong>爻辞</strong></td><td style="text-align:left;">&quot;君子以慎言语，节饮食&quot;</td></tr><tr><td style="text-align:left;"><strong>普光/普明</strong></td><td style="text-align:left;">你们饮食健康、打坐瑜伽→已在颐卦中</td></tr></tbody></table><h3 id="䷛大过——泽灭木-大过" tabindex="-1">䷛大过——泽灭木（大过） <a class="header-anchor" href="#䷛大过——泽灭木-大过" aria-label="Permalink to &quot;䷛大过——泽灭木（大过）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">巽☴下兑☱上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肝（巽）被肺（兑）所克——<strong>金克木太过</strong></td></tr></tbody></table><hr><h2 id="九、坎离——水火之终" tabindex="-1">九、坎离——水火之终 <a class="header-anchor" href="#九、坎离——水火之终" aria-label="Permalink to &quot;九、坎离——水火之终&quot;">​</a></h2><h3 id="䷜坎——水洊至-习坎" tabindex="-1">䷜坎——水洊至（习坎） <a class="header-anchor" href="#䷜坎——水洊至-习坎" aria-label="Permalink to &quot;䷜坎——水洊至（习坎）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">☵☵ 二阴一阳，水象</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>坎水=肾精+元阳</strong>——一点阳气藏在水中</td></tr><tr><td style="text-align:left;"><strong>对应人体</strong></td><td style="text-align:left;">肾、膀胱、骨、髓</td></tr><tr><td style="text-align:left;"><strong>病理</strong></td><td style="text-align:left;">坎水寒→肾阳虚（普光）</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">四逆汤、天魂汤</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">⭐ <strong>普光最核心的卦</strong>——坎水寒，一阳不足</td></tr></tbody></table><h3 id="䷝离——明两作-离火" tabindex="-1">䷝离——明两作（离火） <a class="header-anchor" href="#䷝离——明两作-离火" aria-label="Permalink to &quot;䷝离——明两作（离火）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">☲☲ 二阳一阴，火象</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>离火=心+相火</strong>——外阳内阴</td></tr><tr><td style="text-align:left;"><strong>对应人体</strong></td><td style="text-align:left;">心、小肠、血脉、目</td></tr><tr><td style="text-align:left;"><strong>病理</strong></td><td style="text-align:left;">离火浮越→心火上炎（前胸出汗、口渴）</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">金鼎汤（潜降离火）、黄连阿胶汤</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">前胸出汗多、口渴→离火不降</td></tr><tr><td style="text-align:left;"><strong>普明</strong></td><td style="text-align:left;">潮热烦躁失眠→离火浮越</td></tr></tbody></table><h3 id="坎离交济——水火既济-最核心" tabindex="-1">坎离交济——水火既济（最核心） <a class="header-anchor" href="#坎离交济——水火既济-最核心" aria-label="Permalink to &quot;坎离交济——水火既济（最核心）&quot;">​</a></h3><p><strong>坎水宜升，离火宜降。</strong><strong>水升火降→既济䷾；水寒火浮→未济䷿。</strong></p><p>这不仅是易经的最后一对卦，也是人体健康的核心秘密——普光、普明的所有治疗，最终目标就是<strong>既济</strong>。</p><hr><h2 id="上经与人体对照总表" tabindex="-1">上经与人体对照总表 <a class="header-anchor" href="#上经与人体对照总表" aria-label="Permalink to &quot;上经与人体对照总表&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">卦序</th><th style="text-align:left;">卦名</th><th style="text-align:left;">卦象</th><th style="text-align:left;">人体对应</th><th style="text-align:left;">普光相关</th><th style="text-align:left;">普明相关</th></tr></thead><tbody><tr><td style="text-align:center;">1-2</td><td style="text-align:left;">乾坤</td><td style="text-align:left;">☰☰☷☷</td><td style="text-align:left;">头腹·督任·阴阳</td><td style="text-align:left;">乾阳不足</td><td style="text-align:left;">坤土虚</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">屯</td><td style="text-align:left;">震坎</td><td style="text-align:left;">肾水肝木</td><td style="text-align:left;">⭐水寒木郁</td><td style="text-align:left;"></td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">蒙</td><td style="text-align:left;">坎艮</td><td style="text-align:left;">肾胃</td><td style="text-align:left;">水停中焦</td><td style="text-align:left;">胃虚</td></tr><tr><td style="text-align:center;">5-6</td><td style="text-align:left;">需讼</td><td style="text-align:left;">乾坎/坎乾</td><td style="text-align:left;">阳气与寒水</td><td style="text-align:left;">⭐上热下寒</td><td style="text-align:left;"></td></tr><tr><td style="text-align:center;">7-8</td><td style="text-align:left;">师比</td><td style="text-align:left;">坎坤/坤坎</td><td style="text-align:left;">水湿/脾肾</td><td style="text-align:left;">阴囊湿</td><td style="text-align:left;">白带多</td></tr><tr><td style="text-align:center;">11-12</td><td style="text-align:left;">泰否</td><td style="text-align:left;">乾坤/坤乾</td><td style="text-align:left;">阴阳交泰</td><td style="text-align:left;">⭐<strong>治疗目标</strong></td><td style="text-align:left;"></td></tr><tr><td style="text-align:center;">23-24</td><td style="text-align:left;">剥复</td><td style="text-align:left;">坤艮/震坤</td><td style="text-align:left;">阳尽/阳生</td><td style="text-align:left;">⭐附子作用</td><td style="text-align:left;"></td></tr><tr><td style="text-align:center;">27</td><td style="text-align:left;">颐</td><td style="text-align:left;">震艮</td><td style="text-align:left;">养生</td><td style="text-align:left;">✅正在做</td><td style="text-align:left;">✅正在做</td></tr><tr><td style="text-align:center;">29-30</td><td style="text-align:left;">坎离</td><td style="text-align:left;">坎坎/离离</td><td style="text-align:left;">肾水/心火</td><td style="text-align:left;">⭐坎寒离浮</td><td style="text-align:left;">⭐离浮</td></tr></tbody></table><hr><p><em>本条目为上经三十卦。可与下经三十四卦合参，构成六十四卦完整的人体医学体系。</em></p>`,97)])])}const f=e(r,[["render",d]]);export{y as __pageData,f as default};
